var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"윽, 술 냄새……!","JPN":"うっ、酒臭い……！","ENG":"Ugh, you reek of alcohol...!","TWN":"呃，酒味……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신, 설마 아직도 술 못 끊은 거야?","JPN":"あんた、まさかまだ酒をやめてなかったのか？","ENG":"Oi, you still haven't managed to kick your drinking habit, have you?","TWN":"你難道還沒戒酒嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 하늘에 있는 엄마가 참도 좋아라 하겠네.","JPN":"ったく。天国のお母さんも喜んでるだろうよ。","ENG":"Blimey. Mum must be so happy watching over you in heaven.","TWN":"真是……媽媽在天上知道了，你覺得她會開心嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"집안 꼴은 또 이게 뭐야? 완전 쓰레기 장이 따로 없구만.","JPN":"家の中もめちゃくちゃだな。これじゃ、ゴミ屋敷だ。","ENG":"This place is a dump! Look at all this mess!","TWN":"家裡怎麼這麼髒？簡直就是垃圾場啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"비켜 봐, 청소부터…….","JPN":"どけよ、まずは掃除から……","ENG":"Move outta my way so I can start cleaning–","TWN":"讓開，先讓我打掃一下……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 이건?","JPN":"待て、これは？","ENG":"Hang on, what's this?","TWN":"等一下，這是？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"허! 이젠 하다하다 약까지 손대는 거야?","JPN":"は！　ついには薬にまで手を出したのか？","ENG":"*Scoff!* You're doing drugs now, too?","TWN":"嘖！你現在連毒品都敢碰了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 글러먹은 인간이라는 건, 꼬맹이 시절부터 알고 있었어.","JPN":"あんたがダメ人間ってことは、ガキの頃からわかってたさ。","ENG":"Since I was a kid, I always knew that you were a piece of trash.","TWN":"你這個人有多麼糟糕，其實我從小就知道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 지금까지 매달 꼬박꼬박 이 집에 돈을 부쳤던 건, 엄마가 남긴 유언 때문이야.","JPN":"でも今まで毎月真面目にこの家に仕送りしてたのは、お母さんの遺言のがあったからだ。","ENG":"The only reason why I'm sending you money every month is because of mum's will.","TWN":"我之所以每個月都按時給家裡寄錢一直到現在，都是因為媽媽留下的遺言。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신을 용서하라고. 당신을 부탁한다고…….","JPN":"あんたを許せって、あんたを頼むって……","ENG":"She asked me to forgive you and take care of you...","TWN":"她要我原諒你，把你交給了我……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대답해! 이 망할 아버지!","JPN":"答えろ！　このクソ親父！","ENG":"Answer me, you deadbeat dad!","TWN":"回答我！糟糕的爸爸！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금까지 내가 준 돈으로 이딴 개짓거리를 하고 있었던 거야?","JPN":"今まで俺が渡した金で、こんなことしてたのか？","ENG":"Is this what you were doing with the money I've been sending you?","TWN":"一直以來，你就是用我給你的錢做了這些蠢事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"……콜록, 콜록!","JPN":"……ゲホッ、ゲホッ！","ENG":"...*Cough, Cough!*","TWN":"……咳咳，咳咳！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"크흠, 못 본 사이에 꽤 유명해졌더구나. 로이.","JPN":"ゴホッ、ちょっと見ない間に有名になったじゃないか。ロイ。","ENG":"Errhm, you've become quite famous, haven't you, Roy?","TWN":"咳，好久不見，你變得很出名呢，羅伊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서…… 기관은 때려치고 건틀렛 선수로 살아갈 생각이냐?","JPN":"で……機関はやめてガントレット選手として生きていくつもりか？","ENG":"So... are you thinking of quitting the Institution and becoming a Gauntlet player?","TWN":"所以……你打算離開機關，繼續當聖鎧選手嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"크큭, 그것도 좋겠지. 네놈한테는 길거리 패싸움 수준이 딱 어울리니까 말이야.","JPN":"くくっ、それもいいだろう。お前には道端のケンカがよく似合う。","ENG":"Keke... That's not that bad. Street fights are your thing.","TWN":"呵呵，那也不錯。你這傢伙也就適合在街頭打群架。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"콜록, 콜록! 네놈한테…… <color=#ffd34c>프리드웬</color>은 어울리지 않아.","JPN":"ゲホッ、ゲホッ！　お前に……<color=#ffd34c>プリドウェン</color>は似合わない。","ENG":"*Cough!* *Cough!* <color=#ffd34c>Prydwen</color> isn't a place... for a bloke like you anyway.","TWN":"咳咳，咳咳！你這傢伙……根本配不上<color=#ffd34c>普利多溫</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"그걸 이어받을 자격 같은 건…….","JPN":"あれを受け継ぐ資格なんて……","ENG":"You're not qualified to take over–","TWN":"你沒有接手的資格……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워! 무슨 헛소리를 하는 거야?","JPN":"うるさい！　何をわけのわからないこと言ってるんだ？","ENG":"Shut it! What the hell do you think you're doing?!","TWN":"吵死了！你在胡說八道什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이제와서 부모 노릇이라도 할 셈이야? 내가 뭘 하든 당신이 무슨 상관인데?","JPN":"今さら父親ヅラでもするつもりか？　俺が何をしようと、あんたには関係ないだろ！","ENG":"Think you can parent me now? Why do you care what I do, huh?","TWN":"你現在才想用父親的角色教訓我嗎？我做什麼關你什麼事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 다 집어치워.","JPN":"もういい。","ENG":"Yeah, forget about it.","TWN":"算了，別說廢話了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"난 당신이랑 말 싸움이나 하려고 온 게 아니니까.","JPN":"俺はあんたと喧嘩しに来たわけじゃないんだ。","ENG":"I didn't come here to pick a fight with you.","TWN":"我來這裡不是為了跟你吵架。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 묻고 싶은 건 하나뿐이야.","JPN":"俺が聞きたいのは一つだけ。","ENG":"I just want to ask you one question.","TWN":"我只想問你一個問題。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 한때 프리드웬의 <color=#ffd34c>기관원</color>이었다고 들었어.","JPN":"あんたも一時はプリドウェンの<color=#ffd34c>機関員</color>だったって聞いた。","ENG":"I heard you were also a <color=#ffd34c>member</color> of Prydwen.","TWN":"我聽說你曾經也是普利多溫的<color=#ffd34c>機關成員</color>吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"새디어스인가. 쓸데없는 소리를…….","JPN":"タデウスか。余計なことを……","ENG":"Did Thaddeus say that? That prick...","TWN":"是薩迪烏斯告訴你的？說這些廢話做什麼……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 대체 무슨 짓을 저지른 거야? 기관에게 졌다는 빚이라는 건 또 뭐고?","JPN":"それで、いったい何したんだ？　機関への負い目って、なんのことだよ。","ENG":"What the hell did you do? And what do they mean by you owing the Institution?","TWN":"所以你到底做了什麼？在機關欠下了什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신, 설마 기관을 배신하려 했던 거야?","JPN":"あんた、まさか機関を裏切ろうとしたのか？","ENG":"You didn't... betray the Institution, did you?","TWN":"難道你，曾想背叛機關？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"닥쳐! 닥치라고, 로이 버넷!","JPN":"黙れ！　口を慎め、ロイ・バーネット！","ENG":"Shut up! I said, shut up, Roy Burnett!","TWN":"閉嘴！給我閉嘴，羅伊！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"애송이 주제에 뭘 안다고 까불어! 그건 내 책임이 아니었어!","JPN":"ガキのくせに、わかったふうなこと言うんじゃない！　あれは俺の責任じゃなかったんだ！","ENG":"What does a kid like you know, huh?! None of that was my fault!","TWN":"你這個小鬼懂什麼！那不是我的責任！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇게 될 줄 알았으면 누가! 누가, 그렇게……!","JPN":"ああなると知っていれば誰が！　誰が、あんなこと……！","ENG":"If I knew it would end like that! I'd...! I'd...!","TWN":"早知道會這樣，誰會！誰會，那麼……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"커흑……! 콜록, 콜록!","JPN":"ぐはっ……！　ゲホッ、ゲホッ……！","ENG":"Gah...! *Cough!* *Cough!*","TWN":"咳……！咳咳，咳咳！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"책임?","JPN":"責任？","ENG":"Your fault?","TWN":"責任？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"당장, 당장…… 내 눈앞에서 사라져.","JPN":"今すぐ……俺の目の前から消えろ。","ENG":"Get– Get out... of my sight.","TWN":"馬上，馬上……從我眼前消失。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"어차피 기관에 개가 된 네 녀석이…… 내 말 따위 믿어주지 않겠지!","JPN":"どうせ機関の犬になった貴様が……俺の話なんて信じるわけがない！","ENG":"You're nothing but the Institution's hound... You'll never believe a word I say!","TWN":"反正你這個機關的走狗……不會相信我說的話！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"정 궁금하면, 그 잘나 빠진 새디어스 모건한테 물어보든가.","JPN":"そんなに知りたいのなら、あのお偉いタデウス・モーガンに聞けばいいだろう。","ENG":"If you're that curious to know, go ask that tosser, Thaddeus Morgan.","TWN":"如果你真的想知道，就問問那個自以為是的薩迪烏斯·摩根吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……그래, 뭐 좋아.","JPN":"……そうか、まあいい。","ENG":"...Sure, whatever.","TWN":"……是嗎？好吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 당신한테 제대로 된 이야기를 들을 수 있을 거란 기대는 안 했으니까.","JPN":"どうせあんたからまともな話が聞けるなんて、期待はしてなかったからな。","ENG":"I wasn't expecting to get a straight answer from you, anyway.","TWN":"反正我也沒指望你能說出什麼人話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이거나 먹고 떨어져, 망할 아버지.","JPN":"これでももらっとけ、クソ親父。","ENG":"Take this and piss off, you deadbeat dad.","TWN":"這些給你，離我遠點，糟糕的爸爸。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 돈으로 병원에 가서 병을 고치든, 약에 절어 뒈져버리든 내 알 바 아니야.","JPN":"その金で病院へ行って病気を治すか、薬漬けで死ぬかは俺の知ったことじゃない。","ENG":"Use that money to get treatment, or to shoot up drugs and overdose. I don't give a crap anymore.","TWN":"要麼拿著那些錢去醫院治病，要麼毒死自己，我管不著。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고…… 그게 자식으로서 당신에게 베푸는 마지막 배려니까.","JPN":"それから……それが息子として、俺からあんたにあげる最後の餞別だ。","ENG":"Also... this is the last bit of consideration I'm offering you as your son.","TWN":"還有……這是作為兒子的我，對你最後的照顧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"당장 꺼져 버려, 이 멍청한 녀석!","JPN":"とっとと消えろ、このアホ！","ENG":"Get outta here, you stupid boy!","TWN":"馬上給我滾出去，你這個愚蠢的傢伙！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"지금은 네가 기관에서 특별 대우를 받는 것 같지?","JPN":"今はお前が機関から特別扱いされていると思うだろう？","ENG":"You think you're getting some special treatment from the Institution?","TWN":"你現在是不是覺得在機關能享受特殊待遇？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"하지만 명심해! 너도 결국에는 할아버지처럼 평생을 기관에게 쥐어 짜이다가 버려질 거다!","JPN":"だが、肝に銘じておけ！　お前も結局は爺さんみたいに、一生機関にこき使われて捨てられるんだ！","ENG":"Mark my words! You'll end up exactly like your grandfather, and they will bleed you dry before throwing you away!","TWN":"但是記住了！你終究也會像爺爺一樣一輩子被機關榨乾，然後被拋棄！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"아무런 대가도 받지 못한 채……!","JPN":"何の対価も与えられないまま……！","ENG":"With nothing in return for your services...!","TWN":"甚至得不到任何補償……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 기관은 항상 이런 식이지.","JPN":"ったく。機関はいつもこうだ。","ENG":"Blimey. The Institution is always like this.","TWN":"真是的……這是機關的慣用手法吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"콩가루 집안이긴 해도 그걸 함부로 들추는 게, 당신이 말하던 신사가 할 짓이야?","JPN":"いくらダメな家系でも、そんなものを無闇に暴くのが、あんたの言う紳士のすることなのか？","ENG":"Although I might be from a dysfunctional family, is this what you call being gentlemanly? Snooping around in other people's private lives?","TWN":"就算是亂七八糟的家庭，但隨便揭短，就是你說的紳士會幹的事？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 그만 나오는 게 어때, 모건 할배?","JPN":"そろそろ出てきたらどうだ、モーガンのジジイ。","ENG":"You can stop hiding now, Morgan.","TWN":"還不出來嗎，摩根老頭？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 이거 들켰구만 그래.","JPN":"ふふ、バレていたか。","ENG":"Hah hah, you got me.","TWN":"呵呵，被發現了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"언제부터 눈치챘지? 꽤 감이 날카로워졌는데, 챔피언 버넷.","JPN":"いつから気付いてた？　なかなか鋭くなったな、チャンピオンのバーネット。","ENG":"When did you notice I was there? Looks like your senses have gotten keener, Champion Burnett.","TWN":"你什麼時候開始注意到的？好像變得敏銳囉，冠軍伯內特。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워. 당신이랑 하루이틀 뛴 것도 아니고, 기척도 못 읽을 것 같아?","JPN":"うるさい。あんたとは短い付き合いでもないし、気配くらいはわかる。","ENG":"Shut up. We worked together long enough for me to notice your presence.","TWN":"吵死了，我又不是跟你混一二天而已，這點動靜還聽不出來嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 챔피언 버넷은 또 뭔데?","JPN":"それに、チャンピオンのバーネットってなんだよ。","ENG":"And what's with you calling me \\"Champion Burnett\\"?","TWN":"還有，冠軍伯內特又是什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하! 그거야 내 자랑스러운 제자가 건틀렛 리그를 재패했으니까 말이야!","JPN":"はは！　そりゃあ、我が自慢の弟子がガントレットリーグを制覇したからな！","ENG":"Hah hah! It's because my proud disciple just won the Gauntlet League!","TWN":"哈哈！那當然是因為我引以為傲的徒弟贏得了聖鎧聯賽的冠軍啊！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"물론, 중간에 오지만디아스의 검에 맞아서 리타이어 한 건 정말 안타깝더군.","JPN":"もちろん、途中でオジマンディアスの剣に当たってリタイアしたのはとても残念だった。","ENG":"Although it was a shame that you got injured by Ozymandias and had to retire during the match.","TWN":"當然，中途被奧茲曼迪亞斯擊中而退賽，有點令人惋惜。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정말 안타까워…… 나라면 ","JPN":"本当に残念だ……俺だったら、 ","ENG":"It's a real shame, indeed... If it were me...","TWN":"真是可惜……如果是我的話……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이렇게! ","JPN":"こう！ ","ENG":"I would've avoided her attack like this!","TWN":"就會這樣！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이렇게! 피했을 텐데 말이지.","JPN":"こう！　避けたはずだがな。","ENG":"And this!","TWN":"然後這樣！躲開了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그딴 헛소리나 하려고 내 뒤를 밟은 건 아닐 텐데?","JPN":"そんな話のために俺の後をつけてきたんじゃないだろ？","ENG":"You didn't follow me just to talk gibberish, did you?","TWN":"你不會是為了說那些廢話才跟蹤我的吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 기분 별로니까, 어물쩡 말 돌리려 하지 말고 본론이나 말해.","JPN":"俺は今、機嫌が悪いんだ。無駄話は必要ない。本題を言え。","ENG":"I'm not in a good mood, so cut the crap and get to the point.","TWN":"我現在心情很不好，老頭。別繞彎子了，趕緊說正事吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 젊은이가 참 야박하구만.","JPN":"はは、なんて薄情な若者だ。","ENG":"Hah hah. How rude of you, young man.","TWN":"哈——你這小子還真是無情。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니면 내가 맞춰볼까?","JPN":"それとも、俺が当ててやろうか？","ENG":"Or do you want to me guess?","TWN":"要不我來猜猜看？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기관한테는, 나 역시 <color=#ffd34c>특별 관리 대상</color> 같은 거 아니야?","JPN":"機関にとって俺は<color=#ffd34c>特別管理対象</color>みたいなもんなんだろ？","ENG":"Am I also under <color=#ffd34c>special surveillance</color> by the Institution?","TWN":"對機關來說，我是不是也是<color=#ffd34c>特別管理對象</color>？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"망할 아버지가 대체 무슨 짓을 저질렀는지는 모르겠지만.","JPN":"クソ親父がいったい何をしでかしたのかはわかんないけど。","ENG":"I don't know what kind of trouble my old man caused, but...","TWN":"雖然不知道我那個糟糕的爸爸到底做了什麼。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"정말 배신이라면, 기관은 내가 아버지와 접촉하는 건 피하고 싶을 테니까.","JPN":"本当に裏切りがあったなら、機関は俺が親父と接触するのは避けたいはずだ。","ENG":"if he really did betray the Institution, then they would not want me to contact him.","TWN":"但如果真的是背叛的話，機關肯定不想讓我跟他接觸。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"안 그래? 새디어스 모건?","JPN":"違うか？　タデウス・モーガン。","ENG":"Isn't that right, Thaddeus Morgan?","TWN":"對不對？薩迪烏斯·摩根？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"보기보다 눈치가 빠르군. 그래, 부정하지는 않겠어.","JPN":"思ったより勘がいいな。ああ、否定はしない。","ENG":"Aren't you quick-witted? Yes, I won't deny it.","TWN":"你比我想的還要敏銳呢。好吧，我不否認這些。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 자네를 교육하는 동시에 감시하고 있네.","JPN":"機関は君を教育すると同時に監視している。","ENG":"The Institution is both monitoring and educating you.","TWN":"機關在教育你的同時，也在監視你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜냐하면, 우리에게 <color=#ffd34c>버넷</color>은 무척 <color=#ffd34c>특별한</color> 존재니까 말이야.","JPN":"なぜなら、我々にとって<color=#ffd34c>バーネット</color>はとても<color=#ffd34c>特別な</color>存在だからな。","ENG":"Reason being that, to us, <color=#ffd34c>Burnetts</color> are <color=#ffd34c>special</color> beings.","TWN":"因為對我們來說，<color=#ffd34c>伯內特</color>是非常<color=#ffd34c>特別的</color>存在。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 특별함에는 반드시 그에 걸맞은 <color=#ffd34c>책임</color>이 따르지.","JPN":"そして、特別な者には必ずそれ相応の<color=#ffd34c>責任</color>がついてくる。","ENG":"And with that exceptionality follows great <color=#ffd34c>responsibility</color>.","TWN":"另外，有特別之處就必須遵循對應的<color=#ffd34c>責任</color>。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 아직 자네가 그 책임을 짊어지기에 적절한 인간인지 확인하지 못했어.","JPN":"機関はまだ君がその責任を負うに相応しい人間かどうか、定めきれていないのだよ。","ENG":"However, the Institution has not determined if you are worthy of that responsibility yet.","TWN":"機關還沒有查清楚，你這個人是否適合承擔這個責任。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"책임, 책임…… 지겨워 죽겠네.","JPN":"責任、責任って……もううんざりだ。","ENG":"Responsibility this, responsibility that... I'm so sick of that word.","TWN":"責任，責任……真是煩死了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 항상 이런 식이야. 당신들한테 있어서, 나는 대체 뭐야?","JPN":"機関はいつもそうだ。あんたたちにとって、俺はいったい何だ？","ENG":"The Institution is always like that. What exactly am I to you all?","TWN":"機關總是這樣。對你們來說，我到底算什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할아버지가 어떤 사람이었는지, 아버지가 기관에 무슨 짓을 저질렀는지…….","JPN":"お爺さんがどんな人だったのか、親父が機関に何をしたのか……","ENG":"You've never told me what kind of person Grandfather was, or what my dad did to the Institution...","TWN":"爺爺是什麼樣的人，我爸又對機關做了什麼……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무엇 하나 속 시원하게 알려준 적도 없으면서, 나보고 무작정 책임을 지라고?","JPN":"何一つ教えてくれたこともないくせに、俺に責任を要求するのか？","ENG":"But you just want me to take responsibility for it?","TWN":"什麼都不願意直接告訴我，還想讓我承擔起那些責任？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 내가 뭘 어떻게 해야 날 믿어줄 건데?","JPN":"いったいどうしたら、機関は俺のことを信じてくれるんだよ。","ENG":"What do I have to do to win your trust, huh?","TWN":"你們到底要我怎麼做才會願意相信我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아무래도 뒤늦게 사춘기가 왔나보군, 애송이 버넷.","JPN":"随分と遅い反抗期だな、バーネットの小僧。","ENG":"It seems you've hit late puberty, kid Burnett.","TWN":"看來你進入叛逆期啦，小鬼伯內特。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 하긴 그럴 만도 하겠지. 나도 예전에는 기관이 답답했던 적이 있었으니까.","JPN":"まあ、それもそうか。俺も昔は機関がもどかしくて仕方なかった。","ENG":"But I understand. I too was frustrated with the Institution once.","TWN":"不過，我也能理解你。我以前也有覺得機關很煩的時候。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 자네에게 한 가지 제안을 하지.","JPN":"では、君に一つ提案をしよう。","ENG":"Then, allow me to make you a proposition.","TWN":"那麼，我就給你一個提議吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……제안이라고?","JPN":"……提案？","ENG":"...A proposition?","TWN":"……提議？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 본부</color> 라운드 테이블\\n<color=#ffd34c>로이 버넷</color> 정식 요원 심사","JPN":"<color=#ffd34c>プリドウェン機関本部</color>ラウンドテーブル\\n<color=#ffd34c>ロイ・バーネット</color>正式エージェント審査","ENG":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table\\nOfficial agent evaluation for <color=#ffd34c>Roy Burnett</color>","TWN":"<color=#ffd34c>普利多溫機關總部</color>圓桌會議\\n<color=#ffd34c>羅伊·伯內特</color>正式特工考核中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"요원님, 심사 준비가 완료되었습니다.","JPN":"エージェント、審査の準備ができました。","ENG":"Sir, the preparations are complete.","TWN":"考核已經準備就緒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"버넷 요원이 4번 훈련 시설에서 대기중입니다.","JPN":"エージェント・バーネットが4番訓練施設で待機中です。","ENG":"Agent Burnett is waiting for you in Training room No. 4.","TWN":"伯內特正在4號訓練設施待命。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"...Phew.","TWN":"……呼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠네, 애송이 버넷에게 곧 간다고 전해주게.","JPN":"わかった、バーネットの小僧にすぐ向かうと伝えてくれ。","ENG":"Very well. Tell kid Burnett that I'll be there soon.","TWN":"知道了，告訴小鬼伯內特，我馬上就去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kuh...!","TWN":"咳……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나이가 야속하군, 고작 이까짓 부상 따위에……!","JPN":"歳が憎い。この程度の怪我で……！","ENG":"I'm getting too old for this... How can a small wound like this be so–","TWN":"不服老不行啊，區區這麼點傷就讓我…！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 뭐하는 거죠, 모건?","JPN":"今何をしているのですか、モーガン？","ENG":"Morgan, what are you doing?","TWN":"摩根，你這是在做什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……아가씨? 언제부터?","JPN":"……お嬢様？　いつからそこに？","ENG":"....My lady? How long have you been there?","TWN":"……小姐？你是從什麼時候開始？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 마약성 진통제로군요.","JPN":"これは麻薬性の鎮痛剤ですわね。","ENG":"This is a narcotic painkiller.","TWN":"這是嗎啡止痛劑。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 언제부터 이런 걸 해도 된다고 허락했죠?","JPN":"このような物、私は許可した覚えはありませんけど。","ENG":"I never approved of the use of something like this.","TWN":"我什麼時候開始允許你用這些的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 이거 늙은이가 못난 추태를 보였군요.","JPN":"はは、これは、老人がみっともないところをお見せしてしまった。","ENG":"Hah hah, please excuse this old man's vulgar behaviour.","TWN":"哈哈，讓小姐看到我這個老傢伙狼狽的一面。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 걱정마세요, 아가씨. 제 몸은 제가 가장 잘 아니까요.","JPN":"ご安心ください、お嬢様。自分の体は自分が一番よくわかっています。","ENG":"But don't worry, my lady. I know my body best.","TWN":"不過請放心，小姐。我的身體我自己最清楚。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"닥터 스톱까지 받아 놓고 무슨 헛소리인가요?","JPN":"ドクターストップまでかかっているのに、何を言っているのです？","ENG":"You're being ridiculous. You've even got a doctor stoppage.","TWN":"醫生不是不允許嗎，你在胡說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당장 그만두세요! 이건 기관장 명령입니다. 새디어스 모건!","JPN":"今すぐやめなさい！　これは機関長命令です。タデウス・モーガン！","ENG":"Stop it this instant! This is an order from your chief, Thaddeus Morgan!","TWN":"馬上給我收手！這是機關長的命令，薩迪烏斯·摩根！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물벼룩의 심사는 페리어 요원이 출장에서 복귀할 때까지 연기합니다.","JPN":"ミジンコの審査はエージェント・フェリエーが出張から復帰するまで延期とします。","ENG":"And Water Flea's evaluation will be delayed until Agent Ferrier returns from his business trip.","TWN":"水蚤的考核會延到佩里出差返回後在進行。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 아니라면, 제가 대신 상대를……!","JPN":"それとも、私が代わりに相手を……！","ENG":"Or, better yet, I will do it myself–","TWN":"要不然，我替你……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 한낱 기관원의 심사에 기관장께서 나설 것 까지는 없지 않습니까?","JPN":"ふふ、ただの機関員の審査に機関長が出る必要はありません。","ENG":"Hah hah, but there's no need for the chief to participate in an entry-level evaluation.","TWN":"呵呵，區區機關成員考核，沒有必要由機關長出面吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨…… 앞으로 이 늙은이가 현장을 뛸 수 있는 건, 많아야 두 세번 정도일 겁니다.","JPN":"お嬢様……これからこの老人が現場に出られるのは、多くても2、3回でしょう。","ENG":"My lady... this old man will be able to go out on the field only a couple of more times.","TWN":"小姐……以後我這個老頭能跑現場的機會，最多也就只有二、三次了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워요. 한 번만 더 나이 타령하면 그 입을 꿰매버리겠어요.","JPN":"お黙りなさい。また年齢云々言えば、その口を縫い合わせてしまいますわよ。","ENG":"I've heard enough. If you mention age to me again, I'll sew your mouth up.","TWN":"住嘴，以後要是再用你的年齡當藉口，我就把你的嘴縫上。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어이쿠, 그건 좀 무섭군요.","JPN":"おっと、それはおっかない。","ENG":"Oof... That's a little scary.","TWN":"哎呀，那有點嚇人啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 알고 계시지 않습니까? 제게도 양보할 수 없는 게 있습니다.","JPN":"しかし、ご存知でしょう。俺にも譲れないものがあるんです。","ENG":"But as you may already know, there are matters that I won't entrust to others.","TWN":"可是小姐不是早就知道了嗎？我也有不能讓步的東西。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"전 제가 형님께 물려받은 재주를…… 저 애송이에게 남김없이 전수해야만 합니다.","JPN":"俺は、自分がバーネットから受け継いだ技術を……一つ残らずあの小僧に教えてやらなければ。","ENG":"This skill I inherited from Sir Burnett... I must pass on everything I know to that kid.","TWN":"從大哥那繼承來的一身本事……必須毫無保留地傳授給那個小鬼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그것이 형님을 뛰어넘지 못한 아우가 기관에 바치는 마지막 헌신이 될 테니까요.","JPN":"それこそ、兄を越えられなかった弟が機関に捧げる最後の恩返しです。","ENG":"It will be the last contribution this I, who couldn't surpass him, makes to the Institution.","TWN":"這是無法超越大哥的小弟，最後一次為機關的奉獻。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제겐 이제 시간이 얼마 없습니다.","JPN":"俺にはもう時間がありません。","ENG":"I haven't much time.","TWN":"我沒有多少時間了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이 못난 늙은이의 간청을 들어주시겠습니까?","JPN":"この老人の願いを聞いてくださいますか？","ENG":"So will you please listen to this old man's favour?","TWN":"你能答應我這個沒出息的老頭的懇求嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마음대로 하세요, 이 고집불통!","JPN":"勝手にしなさい、この頑固者！","ENG":"Do as you please! How stubborn can a person be?!","TWN":"隨便你，你這個頑固鬼！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 감사합니다. 아가씨.","JPN":"ふふ、ありがとうございます。お嬢様。","ENG":"Hah hah. Thank you, my lady.","TWN":"哈哈，謝謝小姐。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬은 귀관의 헌신을 결코 잊지 않을 겁니다. 새디어스 모건.","JPN":"プリドウェンは貴官の働きを決して忘れません。タデウス・モーガン。","ENG":"But remember that your contributions to Prydwen will never be forgotten, Thaddeus Morgan.","TWN":"普利多溫永遠不會忘記閣下的奉獻，薩迪烏斯·摩根。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"또한 우리는 귀관의 평온한 여생을 위해, 아낌없는 지원을 약속드립니다.","JPN":"そして、私たちは貴官の平和な余生のため、惜しみない支援を約束しましょう。","ENG":"Also, we promise to keep supporting you so you can spend the rest of the life in peace.","TWN":"此外，我們承諾會為閣下安康的餘生提供不遺餘力的支援。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 최고급 양로원에 감금당하기 싫으면 지금부터라도 은퇴 계획을 세워두세요.","JPN":"最高級の老人ホームに監禁されたくなければ、今からでも引退計画を立てておきなさい。","ENG":"So, if you do not want to be trapped inside a luxury nursing home, I suggest you start planning out your retirement.","TWN":"所以，如果不想被監禁在最高級養老院，最好是從現在開始就立個退休計畫。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 이거 게이트볼 연습이라도 해야겠군요.","JPN":"ふふ、これはゲートボールの練習でもしておくべきですな。","ENG":"Hah hah, perhaps I should start brushing up on my gateball skills.","TWN":"呵呵，看來我得練練槌球了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 왜 이렇게 늦어? 기다리느라 목 빠지는 줄 알았다고.","JPN":"ったく。なんでこんな遅いんだ？　待ちくたびれたじゃないか。","ENG":"Blimey, what took you so long? I was dying of boredom in here.","TWN":"真是的，怎麼來這麼晚？我等到花都要謝了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 미안하네. 애송이 버넷.","JPN":"はは、悪いな。バーネットの小僧。","ENG":"Hah hah, sorry about that, kid Burnett.","TWN":"哈哈，抱歉抱歉，小鬼伯內特。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"리그에서 다친 다리는 좀 괜찮은가?","JPN":"リーグで怪我した足は大丈夫か？","ENG":"How's your injured leg?","TWN":"聯賽那時受傷的腿好點了吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럭저럭 움직일 만해. 집사 할배가 관리하는 회복실이 성능은 끝내주잖아.","JPN":"なんとか動ける。執事のジジイが管理する回復室は、性能がいいからな。","ENG":"It could be better, but I've no problem moving it. You know how great the butler's recovery room is, right?","TWN":"馬馬虎虎能動一點吧。管家老頭的那間醫療室性能很棒，大家不是都知道嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아쉽군. 라이언이 심사 상대였다면 그런 아부가 통했을 텐데 말이지.","JPN":"残念だったな。ライアンが審査相手だったら、そんなおべっかも通じていただろうに。","ENG":"What a shame. If Ryan was your opponent, that kind of flattery would've worked on him.","TWN":"真可惜，要是瑞安在這裡，這種阿諛奉承肯定行得通。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 젊다고 함부로 몸을 굴리다간 나중에 후회하게 될 걸세.","JPN":"だが若いからといって体を酷使すれば、後で後悔することになるぞ。","ENG":"But don't go around stressing your body or you'll regret it later.","TWN":"還有不要因為年輕就把身體不當一回事，以後有你後悔的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아하, 그러셔? 그럼 몸 안 상하게 적당히 좀 봐 달라고.","JPN":"へぇ、そうか？　じゃあ俺が怪我しないよう、手を抜いてくれよ。","ENG":"Oh, yeah? Then how about you go easy on me, eh?","TWN":"啊哈，是嗎？那你就通融一下吧，省得傷了我的身體。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그건 거절하지.","JPN":"はは、それは断る。","ENG":"Hah hah, I'll have to decline.","TWN":"呵呵，我拒絕。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"약속은 잊지 않았겠지, 모건 할배? 한 입으로 두 말하기 없기야.","JPN":"約束は忘れてないよな、モーガンのジジイ？　後で掌を返すのはナシだからな。","ENG":"I hope you didn't forget your promise, Morgan? Man's gotta keep his word.","TWN":"你沒有忘記約定吧，摩根老頭？可不要出爾反爾。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"약속하지. 자네가 이 심사를 통과한다면, 더는 숨기는 것 없이 모든 걸 알려주겠네.","JPN":"約束しよう。君がこの審査に合格したら、すべてを教えてやる。","ENG":"Of course. If you pass this test, I'll tell you everything.","TWN":"我保證，只要你透過了這個考核，我就會毫無保留地把一切都告訴你。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정식 요원이 된다면 알고 싶지 않아도 알아야 하니까.","JPN":"正式なエージェントになれば、嫌でも知る必要があるからな。","ENG":"Well, you'll need to know about it if you officially become an agent anyway.","TWN":"等成為了正式特工後，即使你不想知道也會知道。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"물론, 제한 시간동안 자네가 날 한 대라도 때릴 수 있다면 말이지.","JPN":"もちろん、制限時間内に君が俺に一発でも食らわすことができれば話だが。","ENG":"But that is only if you can hit me once within the time limit.","TWN":"當然，前提是你能在規定時間內能打中我，哪怕是一拳也好。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이랑 처음 만났을 때가 떠오르네.","JPN":"あんたと初めて会った時を思い出すよ。","ENG":"This reminds me of the first time we met.","TWN":"我想起了和你第一次見面的時候。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그때는 본의 아니게, 할배에게 신세를 좀 졌는데 말이야.","JPN":"あの時は不本意ながらも、ジジイには世話になったけどさ。","ENG":"I owe you one at that time, actually.","TWN":"當時，無意中欠了你一點人情。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그때의 나와 지금 이 자리의 내가 같은 사람이라고 생각하면 오산일 거야, 할배.","JPN":"でもあの時の俺と今の俺を同じだと思ったら大間違いだぞ、ジジイ。","ENG":"But if you think I'm still the same kid, you're making a big mistake, old chap.","TWN":"但是，如果認為那時的我和現在的我還是同一個人，那就大錯特錯了，老頭。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"호오? 그거 우연이로군.","JPN":"ほう？　それは奇遇だな。","ENG":"Ho-oh. What a coincidence.","TWN":"喔？那太巧了。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"때마침 나도 옛날 생각을 하던 참이었네, 애송이 버넷.","JPN":"ちょうど俺も昔を思い出していたところだ、バーネットの小僧。","ENG":"I was also thinking about the old days, kid Burnett.","TWN":"正好我也在想以前的事，小鬼伯內特。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나 역시 지금 자네처럼 버넷 형님께 심사를 받았거든.","JPN":"俺も昔、今の君のようにバーネットに審査してもらった。","ENG":"You see, it was Sir Burnett who conducted my test.","TWN":"我也像現在的你一樣，接受了伯內特大哥的考核。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 할배가 정식 요원이 됐다는 건, 그 잘난 우리 할배한테 한 방 먹여줬나 봐?","JPN":"モーガンのジジイが正式エージェントになったってことは、あの偉い俺のジジイに一発食らわしたのか？","ENG":"And seeing how you're here as an official agent, it must mean you gave him one hell of a punch, eh?","TWN":"能當上正式特工，就表示你給了我那個了不起的爺爺一拳吧？"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 그래. 한 방 먹여드렸지.","JPN":"ふふ、そうだ。一発食らわせてやったさ。","ENG":"Hah hah, correct. I did hit him good.","TWN":"呵呵，沒錯，扎實的一拳。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……72번의 재시도 끝에. 라이언과 함께 기습해서 간신히.","JPN":"……72回の再試験でな。ライアンと一緒に奇襲して、ようやくだ。","ENG":"...But only after 72 attempts, I managed to pull it off by ambushing him with Ryan.","TWN":"……在第72次挑戰中，和瑞安一起偷襲，才好不容易取勝。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"과연 자네는 몇 번만에 통과할 수 있을까?","JPN":"果たして、君は何回目で合格できるかな？","ENG":"Now, let's see how long it'll take you.","TWN":"那你究竟又要挑戰幾次呢？"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아무쪼록 통과하고 싶다면 수단과 방법을 가리지 말아야 할 거야, 애송이 버넷.","JPN":"合格したいのなら、手段と方法は選ばないことだ､バーネットの小僧。","ENG":"If you want to pass, you'd better use any means necessary. Got that, kid Burnett?","TWN":"總之，想要順利通過的話，就要不擇手段，小鬼伯內特。"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};